import React, { useState } from 'react';
const App = () => {
  const [filterState, setFilterState] = useState({ category: '', author: '' });
  const [mediaLibrary, setMediaLibrary] = useState([]);
  const [analytics, setAnalytics] = useState({ views: 0, likes: 0 });
  const handleFilterChange = (event) => {
    setFilterState({ ...filterState, [event.target.name]: event.target.value });
  };
  const handleMediaUpdate = (media) => {
    setMediaLibrary((prevMedia) => [...prevMedia, media]);
  };
  const updateAnalytics = () => {
    setAnalytics((prevAnalytics) => ({ ...prevAnalytics, views: prevAnalytics.views + 1 }));
  };
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex flex-col items-center justify-center">
      <div className="bg-[#C06C88] p-4 w-300 h-200 rounded-md shadow-md mb-4">
        <h2 className="text-2xl font-bold">Content Library</h2>
        <input type="text" name="category" value={filterState.category} onChange={handleFilterChange} placeholder="Category" className="p-2 w-full mb-2"/>
        <input type="text" name="author" value={filterState.author} onChange={handleFilterChange} placeholder="Author" className="p-2 w-full mb-2"/>
        <button className="bg-[#411C56] p-2 text-white rounded-md" onClick={() => updateAnalytics()}>Update Analytics</button>
      </div>
      <div className="bg-[#B7D7CD] p-4 w-200 h-50 rounded-md shadow-md">
        <h2 className="text-xl font-bold">Analytics</h2>
        <p>Views: {analytics.views}</p>
        <p>Likes: {analytics.likes}</p>
      </div>
    </div>
  );
};
export default App;
